// FiberServerOptions provides options for the Fiber server.
type FiberServerOptions struct {
	BaseURL     string
	Middlewares []MiddlewareFunc
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router fiber.Router, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, FiberServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router fiber.Router, si ServerInterface, options FiberServerOptions) {
	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	for _, m := range options.Middlewares {
		router.Use(fiber.Handler(m))
	}

	router.Post(options.BaseURL+"/auth/login", wrapper.Login)

	router.Post(options.BaseURL+"/auth/logout", wrapper.Logout)

	router.Post(options.BaseURL+"/auth/refresh", wrapper.RefreshToken)

	router.Post(options.BaseURL+"/auth/register", wrapper.Register)

	router.Get(options.BaseURL+"/cities", wrapper.ListCities)

	router.Post(options.BaseURL+"/cities", wrapper.CreateCity)

	router.Delete(options.BaseURL+"/cities/:id", wrapper.DeleteCity)

	router.Get(options.BaseURL+"/cities/:id", wrapper.GetCity)

	router.Put(options.BaseURL+"/cities/:id", wrapper.UpdateCity)

	router.Get(options.BaseURL+"/countries", wrapper.ListCountries)

	router.Post(options.BaseURL+"/countries", wrapper.CreateCountry)

	router.Get(options.BaseURL+"/countries/:countryId/cities", wrapper.ListCitiesByCountry)

	router.Delete(options.BaseURL+"/countries/:id", wrapper.DeleteCountry)

	router.Get(options.BaseURL+"/countries/:id", wrapper.GetCountry)

	router.Put(options.BaseURL+"/countries/:id", wrapper.UpdateCountry)

	router.Get(options.BaseURL+"/documents", wrapper.ListDocuments)

	router.Post(options.BaseURL+"/documents", wrapper.CreateDocument)

	router.Delete(options.BaseURL+"/documents/:id", wrapper.DeleteDocument)

	router.Get(options.BaseURL+"/documents/:id", wrapper.GetDocument)

	router.Put(options.BaseURL+"/documents/:id", wrapper.UpdateDocument)

	router.Post(options.BaseURL+"/documents/:id/items", wrapper.AddDocumentItem)

	router.Delete(options.BaseURL+"/documents/:id/items/:itemId", wrapper.DeleteDocumentItem)

	router.Put(options.BaseURL+"/documents/:id/items/:itemId", wrapper.UpdateDocumentItem)

	router.Get(options.BaseURL+"/health", wrapper.HealthCheck)

	router.Get(options.BaseURL+"/items", wrapper.ListItems)

	router.Post(options.BaseURL+"/items", wrapper.CreateItem)

	router.Delete(options.BaseURL+"/items/:id", wrapper.DeleteItem)

	router.Get(options.BaseURL+"/items/:id", wrapper.GetItem)

	router.Put(options.BaseURL+"/items/:id", wrapper.UpdateItem)

	router.Get(options.BaseURL+"/users", wrapper.ListUsers)

	router.Get(options.BaseURL+"/users/me", wrapper.GetCurrentUser)

	router.Put(options.BaseURL+"/users/me", wrapper.UpdateCurrentUser)

	router.Put(options.BaseURL+"/users/me/password", wrapper.ChangePassword)

	router.Delete(options.BaseURL+"/users/:id", wrapper.DeleteUser)

	router.Get(options.BaseURL+"/users/:id", wrapper.GetUser)

}

